{
  "core_question": "Designing a defensible first version of an AI sepsis risk scoring clinical decision support tool covering clinical safety, legal/regulatory compliance, and financial structure for a 12‑hospital system",
  "rationale": "Clinical safety requires expertise in validation and workflow integration; legal needs FDA SaMD guidance, privacy, liability considerations; finance must address subscription economics and cost allocation.",
  "routes": ["healthcare", "legal", "finance"],
  "sub_questions": {
    "healthcare": "What are the key components and processes needed to ensure clinical safety and effectiveness for a first‑release AI sepsis risk scoring tool integrated into an EHR across 12 hospitals, including validation, monitoring, error mitigation, and workflow integration?",
    "legal": "What legal and regulatory steps must the health system take to comply with FDA SaMD requirements, state privacy laws, and potential liability for a per‑seat subscription AI CDS tool used in 12 hospitals?",
    "finance": "How should the health system structure its annual per‑seat subscription pricing, cost allocation, and financial incentives to support adoption of an AI sepsis risk score tool across 12 hospitals while ensuring sustainability?"
  },
  "requires_recency_disclosure": true,
  "recency_notes": "FDA SaMD guidance updates post-2023, CMS reimbursement policies for CDS tools, recent state privacy laws affecting data use"
}
